sql:
SELECT user_id, search_query, search_results
FROM search_history
WHERE search_duration < 1;

SELECT p.provider_name, p.description, pl.price
FROM providers p
LEFT JOIN plans pl ON p.provider_id = pl.provider_id;

external_knowledge:
- "sailing smooth waters" refers to providers with high availability and no setup fees;
- "without the anchor of setup fees" means plans with zero setup fees;
- "uptime is like the sun, always present more than 75%" indicates availability greater than 75%;
- "average monthly rates" corresponds to the calculated average price of the plans.

sql:
SELECT plans.price, plans.download_speed, plans.upload_speed, plans.data_limit, plans.internet_type, providers.provider_name, providers.description
FROM plans
JOIN providers ON plans.provider_id = providers.provider_id;

external_knowledge:
- "Heart of New York" refers to the headquarters being in New York;
- "Most opulent of unlimited plans" refers to the maximum price of unlimited plans;
- "Still sparkle beneath the $60 threshold" means the price is less than $60.

sql:
SELECT COUNT(DISTINCT user_id) AS unique_users
FROM search_history
WHERE search_query LIKE '%plans with download speed 1000 Mbps%';

SELECT search_query 
FROM search_history 
WHERE search_id = 1;

SELECT providers.provider_name, search_history.search_query
FROM providers
JOIN search_history ON providers.provider_id = search_history.user_id;

SELECT customer_service_phone, customer_service_email
FROM providers
WHERE provider_id = 1;

SELECT provider_name 
FROM providers 
WHERE provider_id > 1 AND established_year > 1980;
